use std::fs;
use std::path::Path;

pub fn generate(_generated_dir: &Path, styles_dir: &Path) -> std::io::Result<()> {
    let output = styles_dir.join("canonrs.css");

    let mut content = String::from(
"/* 🔒 AUTO-GENERATED - DO NOT EDIT */
/* Generated by tokens-engine - CanonRS Cascata */

/* 0. FONTS */
@import \"./.generated/fonts.css\";

/* 1. PRIMITIVES */
@import \"./.generated/primitives.css\";

/* 2. FOUNDATION */
@import \"./.generated/core.css\";

/* 3. THEMES */
@import \"./.generated/themes.css\";

/* 4. SEMANTIC */
@import \"./.generated/semantic.css\";

/* 5. COMPONENTS */
");

    let components = [
        "components-overlay", "components-selection", "components-forms",
        "components-navigation", "components-feedback", "components-data",
        "components-composite", "components-layout", "components-animation", "components-blocks",
        "foundation-layers",
        "system-opacity", "system-focus", "system-transform", "system-blur",
    ];

    for component in &components {
        content.push_str(&format!("@import \"./.generated/{}.css\";\n", component));
    }

    content.push_str("\n/* 6. ROOT */\n@import \"./.generated/root.css\";\n");

    content.push_str("\n/* 7. VARIANTS */\n");
    let variants_dir = styles_dir.join("variants");
    if variants_dir.exists() {
        for entry in fs::read_dir(variants_dir)? {
            let entry = entry?;
            if let Some(name) = entry.file_name().to_str() {
                if name.ends_with(".css") {
                    content.push_str(&format!("@import \"./variants/{}\";\n", name));
                }
            }
        }
    }

    content.push_str("\n/* 8. UI COMPONENTS */\n@import \"./ui/ui.css\";\n");
    content.push_str("\n/* 9. BLOCKS */\n@import \"./blocks/blocks.css\";\n");
    content.push_str("\n/* 9.1 LAYOUT PRIMITIVES CSS */\n@import \"./layout_primitives/layout_primitives.css\";\n");
    content.push_str("\n/* 10. LAYOUTS */\n@import \"./layouts/layouts.css\";\n");
    content.push_str("\n/* 11. GLOBALS (FINAL) */\n@import \"./tokens/base/globals.css\";\n");

    fs::write(&output, content)?;
    println!("  ✓ canonrs.css (ordem canônica corrigida)");
    Ok(())
}
